ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?address WHERE {
  ?studio a :Studio .
  ?studio p:address ?address .
  ?studio p:genre ?genre_f .
  FILTER(STR(?genre_f) = STR("Comedy"))
} }
  component_2: { SELECT ?studio_name WHERE {
  ?studio a :Studio .
  ?studio p:studio_name ?studio_name .
  ?studio p:genre ?genre_f .
  FILTER(STR(?genre_f) = STR("Comedy"))
} }
  full: { SELECT ?studio_name ?address WHERE {
  ?studio a :Studio .
  ?studio p:studio_name ?studio_name .
  ?studio p:address ?address .
  ?studio p:genre ?genre_f .
  FILTER(STR(?genre_f) = STR("Comedy"))
} }
}

